from libs.money import Money


def test_clamp_raises_to_floor():
    assert Money(10).clamp(Money(25), Money(120)) == Money(25)


def test_clamp_lowers_to_cap():
    assert Money(200).clamp(Money(25), Money(120)) == Money(120)


def test_clamp_inside_bounds_unchanged():
    assert Money(80).clamp(Money(25), Money(120)) == Money(80)


def test_clamp_open_ended_bounds():
    assert Money(5).clamp(Money(20), None) == Money(20)
    assert Money(500).clamp(None, Money(90)) == Money(90)
    assert Money(7).clamp(None, None) == Money(7)


def test_clamp_bounds_equal_pins_amount():
    assert Money(1).clamp(Money(30), Money(30)) == Money(30)


def test_clamp_rejects_inverted_bounds():
    with pytest.raises(ValueError):
        Money(50).clamp(Money(100), Money(10))

