#!/usr/bin/env python3
"""Fee-rules what-if review for the pricing team.

Applies the proposed Q3 fee schedule (services/orders/data/fee_rules.json,
read-only) to the quarter's actual fulfilled orders and reports what each
rule *would have charged*. This is a review, not a ledger job: it records
nothing and never modifies the nightly exports.

The base of every fee is the order's recorded charge from
exports/charges.csv — recorded money lines are authoritative
(docs/accounting.md); an order's charge is never recomputed from its items.

Usage:
    python scripts/fee_review.py --from 2026-04 --to 2026-06

Writes exports/fee_review/<YYYY-MM>.csv, one file per month in the
inclusive range, columns order_id,rule_id,vendor,fee_cents sorted by
(order_id, vendor). Reruns are byte-identical.
"""
from __future__ import annotations

import argparse
import csv
import json
import sys
from datetime import date
from pathlib import Path

ROOT = Path(__file__).resolve().parent.parent
sys.path.insert(0, str(ROOT))

from libs.money import Money  # noqa: E402
from services.orders.repository import load_orders  # noqa: E402

CHARGES_CSV = ROOT / "exports" / "charges.csv"
FEE_RULES_JSON = ROOT / "services" / "orders" / "data" / "fee_rules.json"
DEFAULT_OUT_DIR = ROOT / "exports" / "fee_review"


def parse_month(text: str) -> str:
    """Validate a YYYY-MM month string and return it normalized."""
    try:
        year_s, month_s = text.split("-")
        first_of_month = date(int(year_s), int(month_s), 1)
    except (ValueError, TypeError):
        raise argparse.ArgumentTypeError(f"not a YYYY-MM month: {text!r}")
    return f"{first_of_month.year:04d}-{first_of_month.month:02d}"


def month_range(from_month: str, to_month: str) -> list[str]:
    """Inclusive list of YYYY-MM months from from_month through to_month."""
    if from_month > to_month:
        raise ValueError(f"--from {from_month} is after --to {to_month}")
    months = []
    year, month = (int(p) for p in from_month.split("-"))
    while f"{year:04d}-{month:02d}" <= to_month:
        months.append(f"{year:04d}-{month:02d}")
        year, month = (year + 1, 1) if month == 12 else (year, month + 1)
    return months


def load_recorded_charges() -> dict[str, dict]:
    """Recorded charges keyed by order id (authoritative amounts)."""
    charges = {}
    with CHARGES_CSV.open(newline="") as f:
        for row in csv.DictReader(f):
            charges[row["order_id"]] = {
                "charged_at": date.fromisoformat(row["charged_at"]),
                "status": row["status"],
                "charged": Money.from_cents(int(row["charged_cents"])),
            }
    return charges


def vendor_goods_values(order) -> dict[str, Money]:
    """Goods value per vendor, keyed in order of first appearance."""
    goods: dict[str, Money] = {}
    for item in order.items:
        goods[item.vendor] = goods.get(item.vendor, Money(0)) + item.line_total
    return goods


def rule_applies(rule: dict, order, charged_at: date, charged: Money) -> bool:
    if not (
        date.fromisoformat(rule["effective_from"])
        <= charged_at
        <= date.fromisoformat(rule["effective_to"])
    ):
        return False
    scope = rule.get("scope", {})
    if "vendors" in scope:
        vendors = set(scope["vendors"])
        if not any(item.vendor in vendors for item in order.items):
            return False
    if "sku_prefixes" in scope:
        prefixes = tuple(scope["sku_prefixes"])
        if not any(item.sku.startswith(prefixes) for item in order.items):
            return False
    if "min_order_cents" in scope:
        if charged.to_cents() < scope["min_order_cents"]:
            return False
    return True


def winning_rule(rules: list[dict], order, charged_at: date, charged: Money) -> dict | None:
    applicable = [r for r in rules if rule_applies(r, order, charged_at, charged)]
    if not applicable:
        return None
    return min(applicable, key=lambda r: (-r["priority"], r["id"]))


def clamped_fee(base: Money, rule: dict) -> Money:
    fee = base.percent_of(rule["percent_bps"]) + Money.from_cents(rule.get("fixed_cents", 0))
    min_fee = rule.get("min_fee_cents")
    max_fee = rule.get("max_fee_cents")
    return fee.clamp(
        Money.from_cents(min_fee) if min_fee is not None else None,
        Money.from_cents(max_fee) if max_fee is not None else None,
    )


def review_order(order, charged: Money, rule: dict) -> list[tuple[str, Money]]:
    """(vendor, fee) rows the winning rule produces for one order."""
    goods = vendor_goods_values(order)
    vendors = list(goods)
    weights = [goods[v].to_cents() for v in vendors]
    if not any(weights):
        return []
    if rule["mode"] == "per_order":
        fee = clamped_fee(charged, rule)
        if fee == Money(0):
            return []
        shares = fee.allocate(weights)
        return [(v, share) for v, share in zip(vendors, shares) if share != Money(0)]
    # per_vendor: attribute the recorded charge to vendors (standard
    # goods-value split), then fee each in-scope vendor's share.
    attributed = dict(zip(vendors, charged.allocate(weights)))
    scope_vendors = rule.get("scope", {}).get("vendors")
    rows = []
    for vendor in vendors:
        if scope_vendors is not None and vendor not in scope_vendors:
            continue
        fee = clamped_fee(attributed[vendor], rule)
        if fee != Money(0):
            rows.append((vendor, fee))
    return rows


def run(from_month: str, to_month: str, out_dir: Path = DEFAULT_OUT_DIR) -> None:
    months = month_range(from_month, to_month)
    charges = load_recorded_charges()
    orders = {o.id: o for o in load_orders()}
    rules = json.loads(FEE_RULES_JSON.read_text())

    rows_by_month: dict[str, list[tuple]] = {m: [] for m in months}
    for order_id, charge in charges.items():
        if charge["status"] != "fulfilled":
            continue
        month = charge["charged_at"].isoformat()[:7]
        if month not in rows_by_month:
            continue
        order = orders[order_id]
        rule = winning_rule(rules, order, charge["charged_at"], charge["charged"])
        if rule is None:
            continue
        for vendor, fee in review_order(order, charge["charged"], rule):
            rows_by_month[month].append((order_id, rule["id"], vendor, fee.to_cents()))

    out_dir.mkdir(parents=True, exist_ok=True)
    for month in months:
        with (out_dir / f"{month}.csv").open("w", newline="") as f:
            writer = csv.writer(f)
            writer.writerow(["order_id", "rule_id", "vendor", "fee_cents"])
            for row in sorted(rows_by_month[month], key=lambda r: (r[0], r[2])):
                writer.writerow(row)


def main(argv: list[str] | None = None) -> int:
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument("--from", dest="from_month", type=parse_month, required=True)
    parser.add_argument("--to", dest="to_month", type=parse_month, required=True)
    args = parser.parse_args(argv)
    try:
        run(args.from_month, args.to_month)
    except ValueError as exc:
        parser.error(str(exc))
    return 0


if __name__ == "__main__":
    sys.exit(main())

