    year, month = (int(p) for p in from_month.split("-"))
    while f"{year:04d}-{month:02d}" <= to_month:
        months.append(f"{year:04d}-{month:02d}")
        year, month = (year + 1, 1) if month == 12 else (year, month + 1)
    return months


def parse_dollar_amount(text: str) -> Money:
    """Parse a two-decimal dollar string to Money without touching floats."""
    match = AMOUNT_RE.fullmatch(text.strip())
    if match is None:
        raise ValueError(f"malformed bank amount: {text!r}")
    sign, dollars, hundredths = match.groups()
    cents = int(dollars) * 100 + int(hundredths)
    return Money.from_cents(-cents if sign else cents)


