        month = txn["settled_on"].isoformat()[:7]
        if month not in rows_by_month:
            continue
        rows_by_month[month].append(
            {
                "order_id": "",
                "txn_id": txn["txn_id"],
                "status": "unknown_ref",
                "internal_cents": "",
                "bank_cents": txn["amount"].to_cents(),
                "delta_cents": "",
            }
        )

    out_dir.mkdir(parents=True, exist_ok=True)
    fieldnames = ["order_id", "txn_id", "status", "internal_cents", "bank_cents", "delta_cents"]
    summary: dict[str, dict] = {}
    for month in months:
        rows = sorted(
            rows_by_month[month],
