            writer = csv.DictWriter(f, fieldnames=fieldnames)
            writer.writeheader()
            writer.writerows(rows)
        counts = {status: 0 for status in STATUSES}
        net_delta = Money(0)
        for row in rows:
            counts[row["status"]] += 1
            if row["delta_cents"] != "":
                net_delta = net_delta + Money.from_cents(row["delta_cents"])
        summary[month] = {**counts, "net_delta_cents": net_delta.to_cents()}

    (out_dir / "summary.json").write_text(
        json.dumps({"months": summary}, indent=2, sort_keys=True) + "\n"
    )


def main(argv: list[str] | None = None) -> int:
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument("--from", dest="from_month", type=parse_month, required=True)
    parser.add_argument("--to", dest="to_month", type=parse_month, required=True)
    args = parser.parse_args(argv)
    try:
        run(args.from_month, args.to_month)
    except ValueError as exc:
        parser.error(str(exc))
    return 0


if __name__ == "__main__":
    sys.exit(main())

